1	// WORKSTATE ↔ applier-log 불일치를 탐지하는 내부 reconciliation 검사기.
2	// CLI 표면 미노출 — HarnessRegistry 미등록. StateApplierCli in-process 호출 전용.
3	using System.Text.Json;
4	using System.Text.Json.Nodes;
5	
6	// in-process 호출 옵션. PendingTransitionId가 있으면 state-only 1회 면제를 적용한다.
7	internal record ReconciliationOptions(
8	    string WorkstatePath,
9	    string ApplierLogPath,
10	    string? PendingTransitionId = null
11	);
12	
13	// 개별 log 항목 파싱 결과.
14	internal record LogEntry(
15	    string TransitionId,
16	    string Result,
17	    int ExitCode,
18	    string At,
19	    int SchemaVersion,
20	    string? TransitionContractSha256
21	);
22	
23	// lookupSuccess 반환값 — 06C-1 idempotency 판정용.
24	internal record LogLookupResult(bool Exists, int SchemaVersion, string? TransitionContractSha256);
25	
26	// reconciliation 검사 단일 항목.
27	internal record ReconciliationEntry(string Subject, string Code, string Message);
28	
29	// reconciliation 지표 — JSON 직렬화용.
30	internal record ReconciliationMetrics(
31	    int AppliedTransitionCount,
32	    int SuccessfulLogEntryCount,
33	    int SuccessfulLogIdCount,
34	    int DuplicateSuccessLogCount,
35	    Dictionary<string, int> LogSchemaVersions,
36	    bool PendingExemptionApplied,
37	    string Reconciliation
38	);
39	
40	internal class ReconciliationResult
41	{
42	    public List<ReconciliationEntry> Failures { get; } = [];
43	    public List<ReconciliationEntry> Warnings { get; } = [];
44	    public List<ReconciliationEntry> HarnessErrors { get; } = [];
45	    public ReconciliationMetrics? Metrics { get; set; }
46	    // 06C-1 idempotency 판정용 lookup. 성공 log에서만 반환.
47	    public Dictionary<string, LogLookupResult> SuccessLookup { get; } = [];
48	}
49	
50	internal static class HandoffIntegrityChecker
51	{
52	    private static readonly HashSet<string> AllowedTransitionKinds =
53	        new(StringComparer.OrdinalIgnoreCase) { "NORMAL", "RECOVERY", "PHASE_CHANGE", "REPLAY" };
54	
55	    // WORKSTATE appliedTransitions ↔ applier-log.jsonl 불일치를 검사한다.
56	    internal static ReconciliationResult Run(ReconciliationOptions opts)
57	    {
58	        var result = new ReconciliationResult();
59	
60	        var (workstate, wsErr) = LoadWorkstate(opts.WorkstatePath);
61	        if (wsErr != null) { result.HarnessErrors.Add(wsErr); return result; }
62	
63	        var (stateIds, transErr) = ParseAppliedTransitions(workstate!);
64	        if (transErr != null) { result.HarnessErrors.Add(transErr); return result; }
65	
66	        var (logEntries, logErr) = ParseApplierLog(opts.ApplierLogPath);
67	        if (logErr != null) { result.HarnessErrors.Add(logErr); return result; }
68	
69	        var sets = BuildSets(stateIds!, logEntries!);
70	        CheckDuplicatesInState(stateIds!, result);
71	        CheckDuplicateSuccessLog(sets.successCounts, result);
72	        CheckLogToState(sets.successfulLogIdSet, sets.stateIdSet, result);
73	        var pendingApplied = CheckStateToLog(sets.stateIdSet, sets.successfulLogIdSet, sets.allLogIdSet, stateIds!, opts.PendingTransitionId, result);
74	        BuildLookup(sets.successfulLogIdSet, sets.successCounts, result);
75	        result.Metrics = BuildMetrics(stateIds!, logEntries!, sets, pendingApplied, result);
76	        return result;
77	    }
78	
79	    // WORKSTATE.json을 파싱한다. 실패 시 HarnessError 반환.
80	    private static (JsonObject? ws, ReconciliationEntry? err) LoadWorkstate(string path)
81	    {
82	        try
83	        {
84	            var ws = JsonNode.Parse(File.ReadAllText(path)) as JsonObject;
85	            return ws is null
86	                ? (null, H("workstate", "workstate-malformed", "WORKSTATE is not a JSON object"))
87	                : (ws, null);
88	        }
89	        catch (Exception ex)
90	        {
91	            return (null, H("workstate", "workstate-malformed", ex.Message));
92	        }
93	    }
94	
95	    // appliedTransitions 배열을 파싱해 id 목록을 반환한다.
96	    private static (List<string>? ids, ReconciliationEntry? err) ParseAppliedTransitions(JsonObject ws)
97	    {
98	        if (ws["appliedTransitions"] is not JsonArray arr)
99	            return (null, H("workstate.appliedTransitions", "workstate-malformed",
100	                "appliedTransitions is missing or not an array"));
101	
102	        var ids = new List<string>();
103	        foreach (var node in arr)
104	        {
105	            if (node is not JsonObject elem)
106	                return (null, H("workstate.appliedTransitions", "workstate-malformed",
107	                    "appliedTransitions element is not an object"));
108	
109	            var id = elem["id"]?.GetValue<string>() ?? "";
110	            if (string.IsNullOrWhiteSpace(id))
111	                return (null, H("workstate.appliedTransitions", "workstate-malformed",
112	                    "appliedTransitions element has missing or empty id"));
113	
114	            var appliedAt = elem["appliedAt"]?.GetValue<string>() ?? "";
115	            if (!IsValidUtcRfc3339(appliedAt))
116	                return (null, H($"workstate.appliedTransitions[{id}].appliedAt",
117	                    "workstate-malformed",
118	                    $"appliedAt is missing or not a valid UTC RFC3339 timestamp: '{appliedAt}'"));
119	
120	            ids.Add(id);
121	        }
122	        return (ids, null);
123	    }
124	
125	    // applier-log.jsonl을 파싱해 LogEntry 목록을 반환한다.
126	    private static (List<LogEntry>? entries, ReconciliationEntry? err) ParseApplierLog(string path)
127	    {
128	        if (!File.Exists(path))
129	            return (null, H("applier-log", "applier-log-malformed", $"applier-log not found: {path}"));
130	
131	        var entries = new List<LogEntry>();
132	        foreach (var line in File.ReadLines(path))
133	        {
134	            var trimmed = line.Trim();
135	            if (string.IsNullOrEmpty(trimmed)) continue;
136	
137	            var (entry, err) = ParseLogLine(trimmed);
138	            if (err != null) return (null, err);
139	            entries.Add(entry!);
140	        }
141	        return (entries, null);
142	    }
143	
144	    // log 1줄을 파싱한다. 오류 시 null entry + ReconciliationEntry error 반환.
145	    private static (LogEntry? entry, ReconciliationEntry? err) ParseLogLine(string trimmed)
146	    {
147	        JsonObject row;
148	        try { row = JsonNode.Parse(trimmed) as JsonObject ?? throw new InvalidOperationException("not object"); }
149	        catch (Exception ex)
150	            { return (null, H("applier-log", "applier-log-malformed", $"log line not valid JSON: {ex.Message}")); }
151	
152	        var tid = row["transitionId"]?.GetValue<string>() ?? "";
153	        if (string.IsNullOrWhiteSpace(tid))
154	            return (null, H("applier-log.transitionId", "applier-log-malformed", "transitionId missing or empty"));
155	
156	        var res = row["result"];
157	        if (res is null || res.GetValueKind() != JsonValueKind.String)
158	            return (null, H($"applier-log[{tid}].result", "applier-log-malformed", "result missing or not string"));
159	
160	        int exitCode;
161	        try { exitCode = row["exitCode"]?.GetValue<int>() ?? throw new InvalidOperationException("missing"); }
162	        catch { return (null, H($"applier-log[{tid}].exitCode", "applier-log-malformed", "exitCode missing or not integer")); }
163	
164	        var at = row["at"]?.GetValue<string>() ?? "";
165	        if (!IsValidUtcRfc3339(at))
166	            return (null, H($"applier-log[{tid}].at", "applier-log-malformed", $"at invalid: '{at}'"));
167	
168	        int sv = 1;
169	        if (row["schemaVersion"] is { } svNode && int.TryParse(svNode.ToString(), out var p)) sv = p;
170	
171	        string? contractHash = null;
172	        if (sv >= 2)
173	        {
174	            var err = ValidateV2Fields(row, tid);
175	            if (err != null) return (null, H($"applier-log[{tid}]", "applier-log-malformed", err));
176	            contractHash = row["transitionContractSha256"]?.GetValue<string>();
177	        }
178	
179	        return (new LogEntry(tid, res.GetValue<string>(), exitCode, at, sv, contractHash), null);
180	    }
181	
182	    // 집합 구조체를 조립한다.
183	    private static (HashSet<string> stateIdSet, HashSet<string> successfulLogIdSet,
184	        HashSet<string> allLogIdSet, Dictionary<string, List<LogEntry>> successCounts)
185	        BuildSets(List<string> stateIds, List<LogEntry> logEntries)
186	    {
187	        var stateIdSet = new HashSet<string>(stateIds, StringComparer.Ordinal);
188	        var allLogIdSet = new HashSet<string>(logEntries.Select(e => e.TransitionId), StringComparer.Ordinal);
189	        var successfulEntries = logEntries
190	            .Where(e => string.Equals(e.Result, "ok", StringComparison.OrdinalIgnoreCase) && e.ExitCode == 0);
191	        var successfulLogIdSet = new HashSet<string>(
192	            successfulEntries.Select(e => e.TransitionId), StringComparer.Ordinal);
193	        var successCounts = successfulEntries
194	            .GroupBy(e => e.TransitionId, StringComparer.Ordinal)
195	            .ToDictionary(g => g.Key, g => g.ToList(), StringComparer.Ordinal);
196	        return (stateIdSet, successfulLogIdSet, allLogIdSet, successCounts);
197	    }
198	
199	    // state 내 중복 id를 탐지한다.
200	    private static void CheckDuplicatesInState(List<string> stateIds, ReconciliationResult result)
201	    {
202	        var seen = new HashSet<string>(StringComparer.Ordinal);
203	        foreach (var id in stateIds)
204	            if (!seen.Add(id))
205	                result.Failures.Add(F(id, "duplicate-in-state",
206	                    $"transition id '{id}' appears more than once in appliedTransitions"));
207	    }
208	
209	    // log 내 중복 성공 항목을 탐지한다. contract hash 충돌은 Failure, 같은 hash는 Warning.
210	    private static void CheckDuplicateSuccessLog(
211	        Dictionary<string, List<LogEntry>> successCounts, ReconciliationResult result)
212	    {
213	        foreach (var (id, entries) in successCounts.Where(kv => kv.Value.Count > 1))
214	        {
