        }.ToJsonString(JsonOptions));
        return 0;
    }

    Console.Error.WriteLine(new JsonObject
    {
        ["selfTest"] = "handoff-integrity-pending",
        ["verdict"] = "FAIL",
        ["mismatchCount"] = mismatches.Count,
        ["mismatches"] = mismatches,
    }.ToJsonString(JsonOptions));
